// Простой пример распознавания текста
async function recognizeTextFromImage(imageDataUrl) {
    try {
        const result = await Tesseract.recognize(
            imageDataUrl,
            'eng', // Язык: английский
            {
                logger: m => console.log(m) // Логирование прогресса
            }
        );
        return result.data.text;
    } catch (error) {
        console.error('Ошибка распознавания:', error);
        throw error;
    }
}

// Использование
const imageDataUrl = 'data:image/jpeg;base64,...'; // Ваше изображение в формате Base64
recognizeTextFromImage(imageDataUrl).then(text => {
    console.log('Распознанный текст:', text);
});
